import { useMemo } from 'react';
import { useElementsStore } from '../storages/elementsStorage';
import { elType } from '../utis';

const Footer = () => {
  const elements = useElementsStore(state => state.elements);
  const typeFilter = useElementsStore(state => state.typeFilter);

  const countElements = (fn) => {
    let count = 0;
    for (const el of elements.values()) {
      if (fn(el)) count++;
    }
    return count;
  };

  const getCounts = () => {
    const points = countElements((el) => el.type == elType.POINT);
    const lines = countElements((el) => el.type == elType.LINE);
    const polygons = countElements((el) => el.type == elType.POLYGON);
    return {all: elements.size, points: points, lines: lines, polygons: polygons};
  };
  const counts = useMemo(getCounts, [elements]);

  const getShownTypeMsg = () => {
    const type = Array.from(typeFilter.keys())[0];
    const msg = ' показаны только ';
    switch (type) {
      case elType.POINT:
        return msg + 'точки';
      case elType.LINE:
        return msg + 'линии';
      default:
        return msg + 'многоугольники';
    }
  };

  const getHiddenTypeMsg = () => {
    const msg = ' скрыты';
    if (typeFilter.has(elType.POINT)) {
      if (typeFilter.has(elType.LINE)) return ' многоугольники' + msg;
      return ' линии' + msg;
    }
    return ' точки' + msg;
  };

  const getFilterMsg = () => {
    switch (typeFilter.size) {
      case 0:
        return ' всё скрыто';
      case 1:
        return getShownTypeMsg();
      case 2:
        return getHiddenTypeMsg();
      default:
        return ' всё отображено';
    }
  };
  const filterMsg = useMemo(getFilterMsg, [typeFilter]);

  return <div className='footerPan'>
    {`всего ${counts.all};`}
    <img className='buttonIcon' src='/images/pointSelected.svg' alt='point' />{`${counts.points}; `}
    <img className='buttonIcon' src='/images/lineSelected.svg' alt='line' />{` ${counts.lines}; `}
    <img className='buttonIcon' src='/images/polygonSelected.svg' alt='polygon' />{` ${counts.polygons};`}
    {filterMsg}
  </div>
};

export default Footer;